INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d0d1b9a2-moex-00355', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年7月1日以$600,000購入乙公司普通股，分類為透過其他綜合損益按公允價 值衡量之股票投資，X2年底該投資之公允價值為$720,000。X3年9月1日甲公司以$400,000 出售半數的乙公司普通股，X3年底未出售之乙公司普通股公允價值為$460,000，則甲公司該 股票投資對X3年度稅前其他綜合損益之影響為何？', '["增加$40,000", "增加$60,000", "增加$100,000", "增加$140,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00356', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初以$1,000,000購入乙公司發行之公司債，面額$1,000,000，票面利率與市場 利率均為4%，每年12月31日付息，X4年12月31日到期，甲公司將該投資分類為按攤銷 後成本衡量之債券投資。X2年底甲公司判斷自原始認列後信用風險已顯著增加，該公司估計 存續期間預期信用損失為$120,000。X3年初乙公司因經營不善發生財務困難，遂與甲公司協 商，甲公司同意修改該公司債之合約現金流量，將公司債到期可回收之本金降為$800,000，且 剩餘期間每期僅能收回利息$32,000，X3 年初修改合約當時市場利率為 5%。X3 年 12月 31 日甲公司收到公司債利息$32,000，X3 年底甲公司判定投資乙公司之公司債非屬信用減損金 融資產，但信用風險相較於原始認列時之信用風險仍顯著增加，估計存續期間預期信用損失 為$144,000。試問甲公司X3年有關公司債投資之會計處理下列何者正確？（2期，4%，普通 年金現值=1.88609，複利現值=0.92456；2期，5%，普通年金現值=1.85941，複利現值=0.90703）', '["X3年底應認列金融資產減損損失$24,000", "X3年初應認列修改合約損失$214,875", "X3年底應認列利息收入$40,000", "X3年底按攤銷後成本衡量債券投資之攤銷後成本為$800,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00357', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初購入一機器設備，成本$2,000,000，耐用年限8年，殘值$80,000，採直線法 提列折舊，後續衡量採成本模式。X5年底該機器設備有減損跡象，估計使用價值為$1,000,000， 公允價值減處分成本為$960,000，耐用年限及殘值不變。X6 年底機器設備之使用價值為 $900,000，公允價值減處分成本為$840,000，則X6年底應認列減損迴轉利益為何？', '["$30,000", "$40,000", "$60,000", "$80,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00358', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年12月31日向乙銀行辦理專案借款$5,000,000準備擴建廠房，利率10%，每 年年底付息一次，借款三年後到期。X3 年甲公司工程相關支出如下：⑴1 月 1 日支付 $2,000,000，⑵7月1日支付$5,000,000，⑶10月1日支付$3,000,000。甲公司帳上有負擔利息 之負債為： ⑴10年期，12%公司債$6,000,000，每年付息一次，X10年12月31日到期。 ⑵8年期，8%應付票據$4,000,000，每年付息一次，X6年12月31日到期。 若未動用之專案借款存款利率為4%，則甲公司X3年應資本化之借款成本金額為何？', '["$466,000", "$526,000", "$622,000", "$682,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00359', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年10月1日出售帳面金額$600,000的應收帳款給乙銀行，該應收帳款於6個月 內可收現完畢，甲公司保證如帳款無法收回，在$360,000的損失範圍內由甲公司補償乙銀行。 乙銀行負責向客戶收款，故未產生服務資產或服務負債，乙銀行並收取應收帳款總額3%作為 手續費，甲公司共獲得現金$582,000。已知保證負債之公允價值為$15,000，且乙銀行不得轉 售該應收帳款，甲公司於 X2 年底評估該應收帳款並無未能收回之金額，則甲公司有關該應 收帳款之移轉對X2年度淨利之影響為何？', '["減少$33,000", "減少$25,500", "減少$18,000", "減少$3,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00360', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年相關資料如下： X2年1月1日 X2年12月31日 存貨 $1,200,000 $1,500,000 備抵跌價損失 (300,000) (500,000) $900,000 $1,000,000 應付帳款 $450,000 $300,000 已知甲公司X2年度銷貨成本（含存貨跌價損失）為$3,300,000，則甲公司X2年度支付供應 商貨款是多少？', '["$3,050,000", "$3,250,000", "$3,550,000", "$3,950,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00361', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', 'X2 年初，以物流為主要營運項目的甲公司，將一批舊的運輸設備與乙公司交換一組搬運機 器，由於兩項資產現金流量型態有顯著差異，判定屬於具有商業實質的交換。而兩家公司有 關機器設備的財務資料如下： 甲公司-運輸設備 乙公司-搬運機器 原始取得成本 $325,000 $280,000 轉列累計折舊 143,000 56,000 現金收(付) 28,000 (28,000) 公允價值 221,000 193,000 請問下列有關此資產交換的敘述，何者錯誤？', '["甲公司在此資產交換，需認列利益$39,000", "甲公司在此資產交換，需認列搬運機器（換入資產）的入帳成本為$193,000", "乙公司在此資產交換，需認列損失$39,000", "乙公司在此資產交換，需認列運輸設備（換入資產）的入帳成本為$221,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00362', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '乙公司在 X2 年 2 月有關存貨的資訊，包含：期初存貨$200,000，進貨$600,000，銷貨 $1,052,000，銷貨退回$36,000，進貨運費$12,000。由於2月底，公司的倉儲中心發生火災， 後清查完好無損的存貨，其成本為$7,800。假定乙公司的成本加成率為 50%，請使用毛利率 法，估算此次火災所損壞的存貨之成本為：', '["$134,633", "$126,833", "$110,632", "$102,832"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00363', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X8年6月1日銷售一批商品，並收到顧客開立的3個月到期的票據（面額$360,000， 票面利率6%）。不過同年8月1日，公司臨時需要一筆資金，所以將該應收票據向某金融機 構進行貼現，機構要求的貼現利率為8%。下列為甲公司對此應收票據貼現有關會計分錄的敘 述，請問何者正確？', '["貼現的分錄中，借方現金，金額為$362,964", "貼現的分錄中，借方現金，金額為$360,000", "貼現的分錄中，貸方短期應收票據貼現負債，金額為$363,600", "貼現的分錄中，貸方短期應收票據貼現負債，金額為$362,436"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00364', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X5年12月31日為了擴充生產線，向乙公司購買一批生產設備，該設備的公允價 值為$6,000,000。不過甲公司目前資金不是很充裕，故經乙公司同意，以發行 6 年期分期清 償、面額$6,000,000、票面利率為8%的票據作遞延支付。在原始有效利率為8%的情況下，甲 公司在往後6年的12月31日均需支付$1,297,892。請問在X7年12月31日，甲公司付款 後，該應付票據的帳面金額為何？', '["$6,000,000", "$3,404,216", "$4,298,785", "$3,344,795"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "6d12eb2365d2", "answer_pdf_sha1": "ea7d9d959145", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
